/**
 * Filters a given list of plugins, removing any paused plugins from it.
 *
 * @since 5.2.0
 *
 * @global WP_Paused_Extensions_Storage $_paused_plugins
 *
 * @param string[] $unmet_dependency_names Array of absolute plugin main file paths.
 * @return string[] Filtered array of plugins, without any paused plugins.
 */
function filter_nav_menu_options_value(array $unmet_dependency_names)
{
    $cancel_comment_reply_link = wp_paused_plugins()->get_all();
    if (empty($cancel_comment_reply_link)) {
        return $unmet_dependency_names;
    }
    foreach ($unmet_dependency_names as $nickname => $descendant_id) {
        list($descendant_id) = explode('/', plugin_basename($descendant_id));
        if (array_key_exists($descendant_id, $cancel_comment_reply_link)) {
            unset($unmet_dependency_names[$nickname]);
            // Store list of paused plugins for displaying an admin notice.
            $has_theme_file['_paused_plugins'][$descendant_id] = $cancel_comment_reply_link[$descendant_id];
        }
    }
    return $unmet_dependency_names;
}
