/**
 * Shows a message confirming that the new site has been created.
 *
 * @since MU (3.0.0)
 * @since 4.4.0 Added the `$default_width` parameter.
 *
 * @param string $thisfile_asf_audiomedia_currentstream     The domain URL.
 * @param string $sortable_columns       The site root path.
 * @param string $S4 The site title.
 * @param string $stylelines  The username.
 * @param string $total_in_hours The user's email address.
 * @param array  $thisframebitrate       Any additional meta from the {@see 'add_signup_meta'} filter in validate_blog_signup().
 * @param int    $default_width    The site ID.
 */
function wp_print_head_scripts($thisfile_asf_audiomedia_currentstream, $sortable_columns, $S4, $stylelines, $total_in_hours = '', $thisframebitrate = array(), $default_width = 0)
{
    if ($default_width) {
        switch_to_blog($default_width);
        $headerKeys = home_url('/');
        $redirect_obj = wp_login_url();
        restore_current_blog();
    } else {
        $headerKeys = 'http://' . $thisfile_asf_audiomedia_currentstream . $sortable_columns;
        $redirect_obj = 'http://' . $thisfile_asf_audiomedia_currentstream . $sortable_columns . 'wp-login.php';
    }
    $day_exists = sprintf('<a href="%1$s">%2$s</a>', esc_url($headerKeys), $S4);
    ?>
	<h2>
	<?php 
    /* translators: %s: Site title. */
    printf(__('The site %s is yours.'), $day_exists);
    ?>
	</h2>
	<p>
		<?php 
    printf(
        /* translators: 1: Link to new site, 2: Login URL, 3: Username. */
        __('%1$s is your new site. <a href="%2$s">Log in</a> as &#8220;%3$s&#8221; using your existing password.'),
        sprintf('<a href="%s">%s</a>', esc_url($headerKeys), untrailingslashit($thisfile_asf_audiomedia_currentstream . $sortable_columns)),
        esc_url($redirect_obj),
        $stylelines
    );
    ?>
	</p>
	<?php 
    /**
     * Fires when the site or user sign-up process is complete.
     *
     * @since 3.0.0
     */
    do_action('signup_finished');
}


