/**
 * Sends a confirmation request email when a change of user email address is attempted.
 *
 * @since 3.0.0
 * @since 4.9.0 This function was moved from wp-admin/includes/ms.php so it's no longer Multisite specific.
 *
 * @global WP_Error $base_prefix WP_Error object.
 */
function wp_img_tag_add_loading_optimization_attrs()
{
    global $base_prefix;
    $high_priority_element = wp_get_current_user();
    if (!is_object($base_prefix)) {
        $base_prefix = new WP_Error();
    }
    if ($high_priority_element->ID != $_POST['user_id']) {
        return false;
    }
    if ($high_priority_element->user_email != $_POST['email']) {
        if (!is_email($_POST['email'])) {
            $base_prefix->add('user_email', __('<strong>Error:</strong> The email address is not correct.'), array('form-field' => 'email'));
            return;
        }
        if (email_exists($_POST['email'])) {
            $base_prefix->add('user_email', __('<strong>Error:</strong> The email address is already used.'), array('form-field' => 'email'));
            delete_user_meta($high_priority_element->ID, '_new_email');
            return;
        }
        $custom_variations = md5($_POST['email'] . time() . wp_rand());
        $style_fields = array('hash' => $custom_variations, 'newemail' => $_POST['email']);
        update_user_meta($high_priority_element->ID, '_new_email', $style_fields);
        $loaded = wp_specialchars_decode(get_option('blogname'), ENT_QUOTES);
        /* translators: Do not translate USERNAME, ADMIN_URL, EMAIL, SITENAME, SITEURL: those are placeholders. */
        $signatures = __('Howdy ###USERNAME###,

You recently requested to have the email address on your account changed.

If this is correct, please click on the following link to change it:
###ADMIN_URL###

You can safely ignore and delete this email if you do not want to
take this action.

This email has been sent to ###EMAIL###

Regards,
All at ###SITENAME###
###SITEURL###');
        /**
         * Filters the text of the email sent when a change of user email address is attempted.
         *
         * The following strings have a special meaning and will get replaced dynamically:
         * - ###USERNAME###  The current user's username.
         * - ###ADMIN_URL### The link to click on to confirm the email change.
         * - ###EMAIL###     The new email.
         * - ###SITENAME###  The name of the site.
         * - ###SITEURL###   The URL to the site.
         *
         * @since MU (3.0.0)
         * @since 4.9.0 This filter is no longer Multisite specific.
         *
         * @param string $signatures     Text in the email.
         * @param array  $style_fields {
         *     Data relating to the new user email address.
         *
         *     @type string $custom_variations     The secure hash used in the confirmation link URL.
         *     @type string $newemail The proposed new email address.
         * }
         */
        $have_tags = apply_filters('new_user_email_content', $signatures, $style_fields);
        $have_tags = str_replace('###USERNAME###', $high_priority_element->user_login, $have_tags);
        $have_tags = str_replace('###ADMIN_URL###', esc_url(self_admin_url('profile.php?newuseremail=' . $custom_variations)), $have_tags);
        $have_tags = str_replace('###EMAIL###', $_POST['email'], $have_tags);
        $have_tags = str_replace('###SITENAME###', $loaded, $have_tags);
        $have_tags = str_replace('###SITEURL###', home_url(), $have_tags);
        /* translators: New email address notification email subject. %s: Site title. */
        wp_mail($_POST['email'], sprintf(__('[%s] Email Change Request'), $loaded), $have_tags);
        $_POST['email'] = $high_priority_element->user_email;
    }
}
