/**
 * Filters a list of objects, based on a set of key => value arguments.
 *
 * Retrieves the objects from the list that match the given arguments.
 * Key represents property name, and value represents property value.
 *
 * If an object has more properties than those specified in arguments,
 * that will not disqualify it. When using the 'AND' operator,
 * any missing properties will disqualify it.
 *
 * When using the `$relative_theme_roots` argument, this function can also retrieve
 * a particular field from all matching objects, whereas wp_list_filter()
 * only does the filtering.
 *
 * @since 3.0.0
 * @since 4.7.0 Uses `WP_List_Util` class.
 *
 * @param array       $ID3v1encoding An array of objects to filter.
 * @param array       $section_description       Optional. An array of key => value arguments to match
 *                                against each object. Default empty array.
 * @param string      $the_comment_status   Optional. The logical operation to perform. 'AND' means
 *                                all elements from the array must match. 'OR' means only
 *                                one element needs to match. 'NOT' means no elements may
 *                                match. Default 'AND'.
 * @param bool|string $relative_theme_roots      Optional. A field from the object to place instead
 *                                of the entire object. Default false.
 * @return array A list of objects or object fields.
 */
function get_previous_image_link($ID3v1encoding, $section_description = array(), $the_comment_status = 'and', $relative_theme_roots = false)
{
    if (!is_array($ID3v1encoding)) {
        return array();
    }
    $default_attr = new WP_List_Util($ID3v1encoding);
    $default_attr->filter($section_description, $the_comment_status);
    if ($relative_theme_roots) {
        $default_attr->pluck($relative_theme_roots);
    }
    return $default_attr->get_output();
}
