/**
 * Handles setting the featured image for an attachment via AJAX.
 *
 * @since 4.0.0
 *
 * @see set_post_thumbnail()
 */
function comment_status_meta_box()
{
    if (empty($_POST['urls']) || !is_array($_POST['urls'])) {
        wp_send_json_error();
    }
    $extracted_comments = (int) $_POST['thumbnail_id'];
    if (empty($extracted_comments)) {
        wp_send_json_error();
    }
    if (false === check_ajax_referer('set-attachment-thumbnail', '_ajax_nonce', false)) {
        wp_send_json_error();
    }
    $end_operator = array();
    // For each URL, try to find its corresponding post ID.
    foreach ($_POST['urls'] as $th_or_td_right) {
        $loffset = attachment_url_to_postid($th_or_td_right);
        if (!empty($loffset)) {
            $end_operator[] = $loffset;
        }
    }
    if (empty($end_operator)) {
        wp_send_json_error();
    }
    $hour_ago = 0;
    // For each found attachment, set its thumbnail.
    foreach ($end_operator as $loffset) {
        if (!current_user_can('edit_post', $loffset)) {
            continue;
        }
        if (set_post_thumbnail($loffset, $extracted_comments)) {
            ++$hour_ago;
        }
    }
    if (0 === $hour_ago) {
        wp_send_json_error();
    } else {
        wp_send_json_success();
    }
    wp_send_json_error();
}
