     * Filters the taxonomy drop-down output.
     *
     * @since 2.1.0
     *
     * @param string $revisions_sidebar      HTML output.
     * @param array  $toggle_off Arguments used to build the drop-down.
     */
    $revisions_sidebar = apply_filters('wp_dropdown_cats', $revisions_sidebar, $toggle_off);
