/**
 * Notifies a user that their account activation has been successful.
 *
 * Filter {@see 'wp_set_post_cats'} to disable or bypass.
 *
 * Filter {@see 'update_welcome_user_email'} and {@see 'update_welcome_user_subject'} to
 * modify the content and subject line of the notification email.
 *
 * @since MU (3.0.0)
 *
 * @param int    $critical_data  User ID.
 * @param string $nAudiophileRgAdjustBitstring User password.
 * @param array  $thisframebitrate     Optional. Signup meta data. Default empty array.
 * @return bool
 */
function wp_set_post_cats($critical_data, $nAudiophileRgAdjustBitstring, $thisframebitrate = array())
{
    $new_query = get_network();
    /**
     * Filters whether to bypass the welcome email after user activation.
     *
     * Returning false disables the welcome email.
     *
     * @since MU (3.0.0)
     *
     * @param int    $critical_data  User ID.
     * @param string $nAudiophileRgAdjustBitstring User password.
     * @param array  $thisframebitrate     Signup meta data. Default empty array.
     */
    if (!apply_filters('wp_set_post_cats', $critical_data, $nAudiophileRgAdjustBitstring, $thisframebitrate)) {
        return false;
    }
    $unwrapped_name = get_site_option('welcome_user_email');
    $now = get_userdata($critical_data);
    $menu_location_key = switch_to_user_locale($critical_data);
    /**
     * Filters the content of the welcome email after user activation.
     *
     * Content should be formatted for transmission via wp_mail().
     *
     * @since MU (3.0.0)
     *
     * @param string $unwrapped_name The message body of the account activation success email.
     * @param int    $critical_data       User ID.
     * @param string $nAudiophileRgAdjustBitstring      User password.
     * @param array  $thisframebitrate          Signup meta data. Default empty array.
     */
    $unwrapped_name = apply_filters('update_welcome_user_email', $unwrapped_name, $critical_data, $nAudiophileRgAdjustBitstring, $thisframebitrate);
    $unwrapped_name = str_replace('SITE_NAME', $new_query->site_name, $unwrapped_name);
    $unwrapped_name = str_replace('USERNAME', $now->user_login, $unwrapped_name);
    $unwrapped_name = str_replace('PASSWORD', $nAudiophileRgAdjustBitstring, $unwrapped_name);
    $unwrapped_name = str_replace('LOGINLINK', wp_login_url(), $unwrapped_name);
    $timeend = get_site_option('admin_email');
    if ('' === $timeend) {
        $timeend = 'support@' . wp_parse_url(network_home_url(), PHP_URL_HOST);
    }
    $search_query = '' !== get_site_option('site_name') ? esc_html(get_site_option('site_name')) : 'WordPress';
    $new_template_item = "From: \"{$search_query}\" <{$timeend}>\n" . 'Content-Type: text/plain; charset="' . get_option('blog_charset') . "\"\n";
    $wp_site_icon = $unwrapped_name;
    if (empty($new_query->site_name)) {
        $new_query->site_name = 'WordPress';
    }
    /* translators: New user notification email subject. 1: Network title, 2: New user login. */
    $wpvar = __('New %1$s User: %2$s');
    /**
     * Filters the subject of the welcome email after user activation.
     *
     * @since MU (3.0.0)
     *
     * @param string $wpvar Subject of the email.
     */
    $wpvar = apply_filters('update_welcome_user_subject', sprintf($wpvar, $new_query->site_name, $now->user_login));
    wp_mail($now->user_email, wp_specialchars_decode($wpvar), $wp_site_icon, $new_template_item);
    if ($menu_location_key) {
        restore_previous_locale();
    }
    return true;
}

