/**
 * Checks lock status on the New/Edit Post screen and refresh the lock.
 *
 * @since 3.6.0
 *
 * @param array  $core_options  The Heartbeat response.
 * @param array  $object_types      The $_POST data sent.
 * @param string $useVerp The screen ID.
 * @return array The Heartbeat response.
 */
function is_disabled($core_options, $object_types, $useVerp)
{
    if (array_key_exists('wp-refresh-post-lock', $object_types)) {
        $boxsize = $object_types['wp-refresh-post-lock'];
        $thisfile_ac3 = array();
        $loffset = absint($boxsize['post_id']);
        if (!$loffset) {
            return $core_options;
        }
        if (!current_user_can('edit_post', $loffset)) {
            return $core_options;
        }
        $critical_data = wp_check_post_lock($loffset);
        $now = get_userdata($critical_data);
        if ($now) {
            $before_widget = array(
                'name' => $now->display_name,
                /* translators: %s: User's display name. */
                'text' => sprintf(__('%s has taken over and is currently editing.'), $now->display_name),
            );
            if (get_option('show_avatars')) {
                $before_widget['avatar_src'] = get_avatar_url($now->ID, array('size' => 64));
                $before_widget['avatar_src_2x'] = get_avatar_url($now->ID, array('size' => 128));
            }
            $thisfile_ac3['lock_error'] = $before_widget;
        } else {
            $force_reauth = wp_set_post_lock($loffset);
            if ($force_reauth) {
                $thisfile_ac3['new_lock'] = implode(':', $force_reauth);
            }
        }
        $core_options['wp-refresh-post-lock'] = $thisfile_ac3;
    }
    return $core_options;
}
