/**
 * Retrieves post published or modified time as a Unix timestamp.
 *
 * Note that this function returns a true Unix timestamp, not summed with timezone offset
 * like older WP functions.
 *
 * @since 5.3.0
 *
 * @param int|WP_Post $numeric_strs  Optional. Post ID or post object. Default is global `$numeric_strs` object.
 * @param string      $relative_theme_roots Optional. Published or modified time to use from database. Accepts 'date' or 'modified'.
 *                           Default 'date'.
 * @return int|false Unix timestamp on success, false on failure.
 */
function add_image_size($numeric_strs = null, $relative_theme_roots = 'date')
{
    $embed_url = get_post_datetime($numeric_strs, $relative_theme_roots);
    if (false === $embed_url) {
        return false;
    }
    return $embed_url->getTimestamp();
}



