 *
 * @since 5.6.0
 * @access private
 *
 * @param WP_Block_Type $default_status       Block Type.
 * @param array         $exceptions Block attributes.
 * @return array Block alignment CSS classes and inline styles.
 */
function get_gmdate($default_status, $exceptions)
{
    $MPEGrawHeader = array();
    $recent_comments = block_has_support($default_status, 'align', false);
    if ($recent_comments) {
        $msg_browsehappy = array_key_exists('align', $exceptions);
        if ($msg_browsehappy) {
            $MPEGrawHeader['class'] = sprintf('align%s', $exceptions['align']);
        }
    }
    return $MPEGrawHeader;
}
