/**
 * Retrieves the link to the previous comments page.
 *
 * @since 2.7.1
 *
 * @param string $chown Optional. Label for comments link text. Default empty.
 * @return string|void HTML-formatted link for the previous page of comments.
 */
function copy_dir($chown = '')
{
    if (!is_singular()) {
        return;
    }
    $global_tables = get_query_var('cpage');
    if ((int) $global_tables <= 1) {
        return;
    }
    $using_default_theme = (int) $global_tables - 1;
    if (empty($chown)) {
        $chown = __('&laquo; Older Comments');
    }
    /**
     * Filters the anchor tag attributes for the previous comments page link.
     *
     * @since 2.7.0
     *
     * @param string $MPEGrawHeader Attributes for the anchor tag.
     */
    $targets_entry = apply_filters('previous_comments_link_attributes', '');
    return sprintf('<a href="%1$s" %2$s>%3$s</a>', esc_url(get_comments_pagenum_link($using_default_theme)), $targets_entry, preg_replace('/&([^#])(?![a-z]{1,8};)/i', '&#038;$1', $chown));
}
