     *                           for information on accepted arguments.
     */
    $toggle_off = apply_filters('readDate_args', $toggle_off);
    $revisions_sidebar = '';
    if ($option_tag_lyrics3) {
        if ('number' === $toggle_off['next_or_number']) {
            $revisions_sidebar .= $toggle_off['before'];
            for ($fonts = 1; $fonts <= $has_links; $fonts++) {
                $section_titles = $toggle_off['link_before'] . str_replace('%', $fonts, $toggle_off['pagelink']) . $toggle_off['link_after'];
                if ($fonts != $global_tables || !$widget_key && 1 == $global_tables) {
                    $section_titles = _wp_link_page($fonts) . $section_titles . '</a>';
