        } elseif ($widget_key) {
            $revisions_sidebar .= $toggle_off['before'];
            $AllowEmpty = $global_tables - 1;
            if ($AllowEmpty > 0) {
                $section_titles = _wp_link_page($AllowEmpty) . $toggle_off['link_before'] . $toggle_off['previouspagelink'] . $toggle_off['link_after'] . '</a>';
                /** This filter is documented in wp-includes/post-template.php */
                $revisions_sidebar .= apply_filters('readDate_link', $section_titles, $AllowEmpty);
